export type TruncateOptions = { ellipsis?: string };

/**
 * Truncate a string by replacing its middle with an ellipsis (or custom marker) so the result length <= maxLength.
 *
 * See SPEC.md for full specification and examples.
 */
export function truncateMiddle(text: string, maxLength: number, options?: TruncateOptions): string {
  const ellipsis = options?.ellipsis ?? "…"; // default single-character ellipsis

  if (typeof text !== "string") {
    throw new TypeError("text must be a string");
  }

  if (!Number.isFinite(maxLength) || Math.floor(maxLength) !== maxLength) {
    throw new RangeError("maxLength must be a finite integer");
  }

  if (maxLength < 0) {
    throw new RangeError("maxLength must be a non-negative integer");
  }

  // Fast path: no truncation needed
  if (text.length <= maxLength) return text;

  // If maxLength is 0, return empty string
  if (maxLength === 0) return "";

  // If maxLength is smaller than the ellipsis length, return truncated ellipsis
  if (maxLength < ellipsis.length) return ellipsis.slice(0, maxLength);

  // Otherwise, allocate remaining characters to start and end around the ellipsis.
  const remaining = maxLength - ellipsis.length;
  const startLen = Math.ceil(remaining / 2);
  const endLen = Math.floor(remaining / 2);

  const start = text.slice(0, startLen);
  const end = endLen > 0 ? text.slice(text.length - endLen) : "";

  return start + ellipsis + end;
}

import { describe, it, expect } from 'vitest';
import { truncateMiddle } from '../src/index';

describe('truncateMiddle', () => {
  it('returns original when shorter or equal to maxLength', () => {
    expect(truncateMiddle('hello', 5)).toBe('hello');
    expect(truncateMiddle('hi', 10)).toBe('hi');
  });

  it('truncates with default ellipsis preserving start and end', () => {
    const input = 'abcdefghijklmnop'; // length 16
    const out = truncateMiddle(input, 9); // ellipsis length 1 -> remaining 8 -> 4 + 4
    expect(out).toBe('abcd…mnop');
    expect(out.length).toBe(9);
  });

  it('supports a custom ellipsis', () => {
    const input = 'abcdefghijklmnopqrstuvwxyz';
    const out = truncateMiddle(input, 7, { ellipsis: '...' }); // ellipsis len 3 -> remaining 4 -> 2 + 2
    expect(out).toBe('ab...yz');
    expect(out.length).toBe(7);
  });

  it('handles very small maxLength values', () => {
    expect(truncateMiddle('longtext', 0)).toBe('');
    // when maxLength equals ellipsis length, result is the ellipsis
    expect(truncateMiddle('longtext', 1)).toBe('…');
    // when maxLength is smaller than provided ellipsis, ellipsis is truncated
    expect(truncateMiddle('longtext', 2, { ellipsis: '***' })).toBe('**');
  });

  it('throws on invalid maxLength', () => {
    // non-integer
    expect(() => truncateMiddle('x', 2.5)).toThrow();
    // NaN
    expect(() => truncateMiddle('x', NaN)).toThrow();
    // negative
    expect(() => truncateMiddle('x', -1)).toThrow();
  });
});
